1263	func (h *HugoSites) LogServerAddresses() {
1264		if h.hugoInfo.IsMultihost() {
1265			for _, s := range h.Sites {
1266				h.Log.Printf("Web Server is available at %s (bind address %s) %s\n", s.conf.C.BaseURL, s.conf.C.ServerInterface, s.Language().Lang)
1267			}
1268		} else {
1269			s := h.Sites[0]
1270			h.Log.Printf("Web Server is available at %s (bind address %s)\n", s.conf.C.BaseURL, s.conf.C.ServerInterface)
1271		}
