1274	func (h *HugoSites) processFull(ctx context.Context, l logg.LevelLogger, config *BuildCfg) (err error) {
1275		if err = h.processFiles(ctx, l, config); err != nil {
1276			err = fmt.Errorf("readAndProcessContent: %w", err)
1277			return
1278		}
1279		return err
1280	}
