1282	func (s *Site) handleContentAdapterChanges(bi pagesfromdata.BuildInfo, buildConfig *BuildCfg) {
1283		if !s.h.isRebuild() {
1284			return
1285		}
1286	
1287		if len(bi.ChangedIdentities) > 0 {
1288			buildConfig.WhatChanged.Add(bi.ChangedIdentities...)
1289			buildConfig.WhatChanged.needsPagesAssembly = true
1290		}
1291	
1292		for _, p := range bi.DeletedPaths {
1293			pp := paths.AddLeadingSlash(path.Join(bi.Path.Base(), p.Path))
1294			df := func(n contentNode) bool {
1295				if len(p.Hashes) == 0 {
1296					return true
1297				}
1298				if nn, ok := n.(contentNodeSourceEntryIDProvider); ok {
1299					if i, ok := nn.nodeSourceEntryID().(uint64); ok && i != 0 {
1300						if _, found := p.Hashes[i]; found {
1301							return true
1302						}
1303					}
1304				}
1305				return false
1306			}
1307	
1308			if v, count := s.pageMap.treePages.DeleteFuncRaw(pp, df); count > 0 {
1309				buildConfig.WhatChanged.Add(cnh.GetIdentity(v))
1310			}
1311			if v, count := s.pageMap.treeResources.DeleteFuncRaw(pp, df); count > 0 {
1312				buildConfig.WhatChanged.Add(cnh.GetIdentity(v))
1313	
1314				// A deleted resource may affect its parent page.
1315				if _, v := s.pageMap.treePages.LongestPrefiValueRaw(pp); v != nil {
1316					buildConfig.WhatChanged.Add(cnh.GetIdentity(v))
1317				}
1318			}
1319		}
1320	}
1321	
1322	func (h *HugoSites) processContentAdaptersOnRebuild(ctx context.Context, buildConfig *BuildCfg) error {
1323		g := rungroup.Run(ctx, rungroup.Config[*pagesfromdata.PagesFromTemplate]{
1324			NumWorkers: h.numWorkers,
1325			Handle: func(ctx context.Context, p *pagesfromdata.PagesFromTemplate) error {
1326				bi, err := p.Execute(ctx)
1327				if err != nil {
1328					return err
1329				}
1330				s := p.Site.(*Site)
1331				s.handleContentAdapterChanges(bi, buildConfig)
1332				return nil
1333			},
1334		})
1335	
1336		h.pageTrees.treePagesFromTemplateAdapters.WalkPrefixRaw(doctree.LockTypeRead, "", func(key string, p *pagesfromdata.PagesFromTemplate) (bool, error) {
1337			if p.StaleVersion() > 0 {
1338				g.Enqueue(p)
1339			}
1340			return false, nil
1341		})
1342	
1343		return g.Wait()
1344	}
1345	
1346	func (s *HugoSites) processFiles(ctx context.Context, l logg.LevelLogger, buildConfig *BuildCfg, filenames ...pathChange) error {
1347		if s.Deps == nil {
1348			panic("nil deps on site")
1349		}
1350	
1351		sourceSpec := source.NewSourceSpec(s.PathSpec, buildConfig.ContentInclusionFilter, s.BaseFs.Content.Fs)
1352	
1353		// For inserts, we can pick an arbitrary pageMap.
1354		pageMap := s.Sites[0].pageMap
1355	
1356		c := newPagesCollector(ctx, s.h, sourceSpec, s.Log, l, pageMap, buildConfig, filenames)
1357	
1358		if err := c.Collect(); err != nil {
1359			return err
1360		}
1361	
1362		return nil
1363	}
