	}
	var h *hugolib.HugoSites
	h, err = c.hugo()
	if err != nil {
		return
	}
	err = h.Build(hugolib.BuildCfg{NoBuildLock: true, RecentlyTouched: c.visitedURLs, ErrRecovery: c.errState.wasErr()}, events...)
	return
}

