func (w *WhatChanged) init() {
	if w.ids == nil {
		w.ids = make(map[identity.Identity]bool)
	}
}

func (w *WhatChanged) Add(ids ...identity.Identity) {
	w.mu.Lock()
	defer w.mu.Unlock()

	w.init()

	for _, id := range ids {
		w.ids[id] = true
	}
}

